package com.socialblog.interaction.domain;import jakarta.persistence.*;import java.time.Instant;import java.util.UUID;@Entity @Table(name="interactions",uniqueConstraints=@UniqueConstraint(name="uk_interaction_actor_target",columnNames={"actor_id","target_type","target_id"}))public class Interaction{@Id private UUID id;@Column(name="actor_id",nullable=false)private UUID actorId;@Enumerated(EnumType.STRING)@Column(name="target_type",nullable=false)private TargetType targetType;@Column(name="target_id",nullable=false)private UUID targetId;@Column(name="created_at",nullable=false)private Instant createdAt;protected Interaction(){}public Interaction(UUID actor,TargetType type,UUID target){id=UUID.randomUUID();actorId=actor;targetType=type;targetId=target;createdAt=Instant.now();}public UUID getId(){return id;}public UUID getActorId(){return actorId;}public TargetType getTargetType(){return targetType;}public UUID getTargetId(){return targetId;}public Instant getCreatedAt(){return createdAt;}}
